            {
                id = "outlives", speaker = "The Ferryman",
                text = "*(He looks down at his own weathered hands on the pole, and then at the dark water, and a quiet acceptance settles over him.)* Outlive me. *(quietly.)* *Aye.* There's the *thing* I *don't* *say* to the *dead* I *carry.* *(he touches his chest.)* I'm *sixty* *years* at this *pole*, friend, and *one* *bad* *night* — a *slip*, a *chill*, a *heart* that *finally* *stops* *mid-stroke* — and *I'm* the *one* on the *far* *bank*, and *then* — *(he nods at the near bank)* — *then* the *coinless* *wait* *with* *no* *one* to *cross* them, and the *harvest* *takes* the *lot*, and *sixty* *years* of *my* *rule-breaking* *dies* the *night* *I* *do.* *(fiercely.)* That's *Hessa's* *fear*, isn't it — I've *heard* the *dockhands* *speak* of her *underground.* A *mercy* that *needs* *one* *old* *body* is a *countdown*, *not* a *rescue.* *(he plants the pole, decided.)* So — *teach* the *fleet*, *while* I *still* *can.* *Pass* the *pole.* *Show* the *young* *fishers* the *currents*, the *crossing-points*, the *trick* of *poling* a *skiff* *full* of *the* *dead* who *can't* *lift* a *hand.* *(he lifts the tin cup with its single copper.)* And *keep* the *cup.* *Write* the *new* *toll* — *\"for the ones who can't\"* — *into* the *dockside* *rites*, so it's *not* *my* *whim* but a *custom*, *taught*, *handed* *down*, *outliving* *any* *one* *ferryman.* *(he meets your eyes, and there's peace in the weariness.)* When the *river* *takes* *me* — and it *will*, *soon* *enough* — the *coinless* *must* *still* *cross* *free.* *The skiff must not stop because the old man did.* *(he presses the cup toward you.)* *Help* me make the *crossing* a *thing* the *river* *keeps*, *not* a *thing* *one* *old* *man* *does.* *Teach* it, *write* it, *hand* it *on.* *Let* the *coinless* *cross* *free* *long* *after* I'm the *one* being *carried.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "sq.crossing_outlives_him", op = FlagOp.SetTrue }, new FlagClause { key = "act5.unbroken_line", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "rule", speaker = "The Ferryman",
                text = "*(He shakes his head and poles on, the weariness sliding back over him like the current closing over a stone.)* Don't *make* it *grand*, friend. *(quietly.)* I'm *one* *old* *man* who *got* *ashamed* of *watching* the *poor* *taken*, and *broke* a *rule* I *should've* *broken* *years* *ago.* *That's* *all.* *(he works the pole.)* No *fleet*, no *doctrine*, no *grand* *reforging.* Just — *me*, and the *skiff*, and as *many* *as* I can *carry* *before* my *back* *gives* *out.* *(he won't quite meet your eyes.)* It *won't* be *enough.* I *know* it *won't* be *enough.* But *one* *old* *man's* *not-enough* is *still* *more* than the *nothing* I *gave* them for *sixty* *years.* *(he poles toward the far bank.)* *Mind* the *step* if you're *crossing.* The *dusk* *fare's* *free* *now.* It's the *one* *thing* I've *got* *left* to *give*, and I'll *give* it *till* the *river* *takes* the *giving* *hand.* *(and he poles the black skiff out toward the failing light, the old man who broke the church's snare and could not yet imagine his stubbornness becoming anything larger than himself.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Ferryman",
                text = "*(The Ferryman of Chionthar poles his black skiff through the dusk — crossing the breathless, coinless dead free before the near bank's harvesters can take them, the single copper in his tin cup kept against the memory of an old woman who pressed her last coin into his hands \"for the ones who can't\" — and whether you held the bank so the waiting was safe, lit a fleet so the waiting was short, reforged the toll so none were turned back poor, carried to the Court the truth that the waiting-rule was the church's snare and never the god's, or made the crossing a thing the river keeps rather than one old man does, you carry away the sharpest faction-truth the long road draws: that the cruelty was never the god's at all, but a snare the church bolted to his holy coin and called his will — and that the kindest thing you can do for a people taught to fear the wrong master is to teach them, at last, to tell the god's old mercy from the trap that wears its face.)*",
            });

            SqCrossingThreadDialogue = g;
        }
    }
